private streamOpts(label: string, fixedPercent?: number): CallLLMOptions {
    return {
      onChunk: (chars: number) => {
        const tokens = Math.round(chars / 4);
        const pct = fixedPercent ?? this.lastPercent;
        this.onProgress('stream', pct, `${label} (${tokens} tok)`);
      },
    };
  }

