getFileName = (filePath: string): string => {
  const parts = filePath.split('/');
  return parts[parts.length - 1] || filePath;
}

getDirectory = (filePath: string): string => {
  const parts = filePath.split('/');
  parts.pop();
  return parts.join('/') || '';
}

truncateContent = (content: string, maxLength: number): string => {
  if (content.length <= maxLength) {
    return content;
  }

  // Find last space before maxLength to avoid cutting words
  const truncated = content.slice(0, maxLength);
  const lastSpace = truncated.lastIndexOf(' ');

  if (lastSpace > maxLength * 0.8) {
    return truncated.slice(0, lastSpace) + '...';
  }

  return truncated + '...';
}

cleanContent = (content: string): string => {
  return content
    // Normalize line endings
    .replace(/\r\n/g, '\n')
    // Remove excessive blank lines (more than 2)
    .replace(/\n{3,}/g, '\n\n')
    // Trim each line
    .split('\n')
    .map(line => line.trimEnd())
    .join('\n')
    .trim();
}

generateFunctionText = (
  node: EmbeddableNode,
  maxSnippetLength: number
): string => {
  const parts: string[] = [
    `Function: ${node.name}`,
    `File: ${getFileName(node.filePath)}`,
  ];

  const dir = getDirectory(node.filePath);
  if (dir) {
    parts.push(`Directory: ${dir}`);
  }

  if (node.content) {
    const cleanedContent = cleanContent(node.content);
    const snippet = truncateContent(cleanedContent, maxSnippetLength);
    parts.push('', snippet);
  }

  return parts.join('\n');
}

generateClassText = (
  node: EmbeddableNode,
  maxSnippetLength: number
): string => {
  const parts: string[] = [
    `Class: ${node.name}`,
    `File: ${getFileName(node.filePath)}`,
  ];

  const dir = getDirectory(node.filePath);
  if (dir) {
    parts.push(`Directory: ${dir}`);
  }

  if (node.content) {
    const cleanedContent = cleanContent(node.content);
    const snippet = truncateContent(cleanedContent, maxSnippetLength);
    parts.push('', snippet);
  }

  return parts.join('\n');
}

generateMethodText = (
  node: EmbeddableNode,
  maxSnippetLength: number
): string => {
  const parts: string[] = [
    `Method: ${node.name}`,
    `File: ${getFileName(node.filePath)}`,
  ];

  const dir = getDirectory(node.filePath);
  if (dir) {
    parts.push(`Directory: ${dir}`);
  }

  if (node.content) {
    const cleanedContent = cleanContent(node.content);
    const snippet = truncateContent(cleanedContent, maxSnippetLength);
    parts.push('', snippet);
  }

  return parts.join('\n');
}

generateInterfaceText = (
  node: EmbeddableNode,
  maxSnippetLength: number
): string => {
  const parts: string[] = [
    `Interface: ${node.name}`,
    `File: ${getFileName(node.filePath)}`,
  ];

  const dir = getDirectory(node.filePath);
  if (dir) {
    parts.push(`Directory: ${dir}`);
  }

  if (node.content) {
    const cleanedContent = cleanContent(node.content);
    const snippet = truncateContent(cleanedContent, maxSnippetLength);
    parts.push('', snippet);
  }

  return parts.join('\n');
}

generateFileText = (
  node: EmbeddableNode,
  maxSnippetLength: number
): string => {
  const parts: string[] = [
    `File: ${node.name}`,
    `Path: ${node.filePath}`,
  ];

  if (node.content) {
    const cleanedContent = cleanContent(node.content);
    // For files, use a shorter snippet since they can be very long
    const snippet = truncateContent(cleanedContent, Math.min(maxSnippetLength, 300));
    parts.push('', snippet);
  }

  return parts.join('\n');
}

generateEmbeddingText = (
  node: EmbeddableNode,
  config: Partial<EmbeddingConfig> = {}
): string => {
  const maxSnippetLength = config.maxSnippetLength ?? DEFAULT_EMBEDDING_CONFIG.maxSnippetLength;

  switch (node.label) {
    case 'Function':
      return generateFunctionText(node, maxSnippetLength);
    case 'Class':
      return generateClassText(node, maxSnippetLength);
    case 'Method':
      return generateMethodText(node, maxSnippetLength);
    case 'Interface':
      return generateInterfaceText(node, maxSnippetLength);
    case 'File':
      return generateFileText(node, maxSnippetLength);
    default:
      // Fallback for any other embeddable type
      return `${node.label}: ${node.name}\nPath: ${node.filePath}`;
  }
}

generateBatchEmbeddingTexts = (
  nodes: EmbeddableNode[],
  config: Partial<EmbeddingConfig> = {}
): string[] => {
  return nodes.map(node => generateEmbeddingText(node, config));
}

