parseGitHubUrl = (url: string): { owner: string; repo: string } | null => {
  const cleaned = url.trim().replace(/\.git$/, '');
  const match = cleaned.match(/github\.com\/([^\/]+)\/([^\/]+)/);

  if (!match) return null;

  return {
    owner: match[1],
    repo: match[2],
  };
}

